INSERT INTO consulting_case_studies (id, title_es, title_en, description_es, description_en, result_es, result_en, image, sort_order) VALUES
  ('chatbot', 'Chatbot IA para Atención al Cliente', 'AI Chatbot for Customer Service', 'Implementamos un chatbot con IA que responde el 80% de las consultas automáticamente, 24/7, sin intervención humana.', 'We implemented an AI chatbot that automatically answers 80% of inquiries, 24/7, without human intervention.', '−70% tiempo de respuesta, +40% satisfacción del cliente', '−70% response time, +40% customer satisfaction', '/chatbot.jpg', 0),
  ('ventas', 'Dashboard de Ventas en Tiempo Real', 'Real-time Sales Dashboard', 'Creamos un dashboard centralizado que consolida datos de múltiples fuentes y muestra KPIs en tiempo real para la gerencia.', 'We created a centralized dashboard that consolidates data from multiple sources and shows real-time KPIs for management.', '+60% velocidad en toma de decisiones, −5h reportes semanales', '+60% decision-making speed, −5h weekly reports', '/ventas.jpg', 1),
  ('inventario', 'Control de Inventario Automatizado', 'Automated Inventory Control', 'Automatizamos el control de stock con alertas inteligentes que predicen rupturas antes de que ocurran.', 'We automated inventory control with smart alerts that predict stockouts before they happen.', '−90% rupturas de stock, −30% costo de inventario', '−90% stockouts, −30% inventory cost', '/inventario.jpg', 2),
  ('feedback', 'Análisis de Feedback con IA', 'AI-Powered Feedback Analysis', 'Implementamos análisis de sentimiento automático sobre feedback de clientes para detectar problemas críticos en tiempo real.', 'We implemented automatic sentiment analysis on customer feedback to detect critical issues in real time.', '+35% NPS, detección de problemas 4x más rápida', '+35% NPS, 4x faster problem detection', '/feedback.jpg', 3);
